class Solution:
    def pacificAtlantic(self, heights):
        rows, cols = len(heights), len(heights[0])
        def dfs(starts):
            seen = set(starts)
            stack = list(starts)
            while stack:
                r, c = stack.pop()
                for dr, dc in ((1,0),(-1,0),(0,1),(0,-1)):
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < rows and 0 <= nc < cols and (nr, nc) not in seen and heights[nr][nc] >= heights[r][c]:
                        seen.add((nr, nc)); stack.append((nr, nc))
            return seen
        pac = dfs([(r,0) for r in range(rows)] + [(0,c) for c in range(cols)])
        atl = dfs([(r,cols-1) for r in range(rows)] + [(rows-1,c) for c in range(cols)])
        return [[r, c] for r, c in sorted(pac & atl)]
